$filename = $argv[0];
$f = open($filename . '.txt', 'r');
$lines = [];
while (f !== '') {
    $line = f->next();
    if ($line) {
        $lines[] = $line;
    }
}
$f->close();

$word_counts = array();
foreach ($lines as $line) {
    if (empty($line)) continue;
    $words = explode(' ', $line);
    foreach ($words as $word) {
        $trimmed = trim($word);
        if (!empty($trimmed)) {
            $lower_word = strtolower($trimmed);
            if (!isset($word_counts[$lower_word])) {
                $word_counts[$lower_word] = 0;
            }
            $word_counts[$lower_word]++;
        }
    }
}

// Sort the words by frequency in descending order
$sorted_words = [];
foreach ($word_counts as $word => $count) {
    array_unshift($sorted_words, ['$word' => $count]);
}

// Output top 3 most frequent words
top_words = [];
foreach ($sorted_words as $pair) {
    if (count($top_words) < 3 && keys($sorted_words)[0] !== '') {
        top_words[] = array_unshift($top_words, $pair);
    }
}

print_r(top_words);
